# Implemented for NASTaR dataset
# Adapted from ssdd_dataset.py by Kamirul Kamirul
#
# NASTaR: NovaSAR Automated Ship Target Recognition Dataset
# This loader reads the COCO OBB JSON generated by
# convert_NASTaR_to_COCO_OBB_Detectron.py and returns
# a list of dicts in Detectron2's standard dataset format.

import os
import json


def get_nastar_dataset_function(json_path, images_root):
    """
    Returns a callable that loads the NASTaR dataset from a COCO OBB JSON.

    Args:
        json_path:   Path to the COCO OBB JSON file
                     (e.g. eval_json/NASTaR_train_COCO_OBB_Detectron.json)
        images_root: Root directory for resolving image file_name paths.
                     The file_name in the JSON is relative to the NASTaR
                     dataset root (e.g. Data/NovaSAR_.../ship_patches_uint8/...)
                     so images_root should be the NASTaR dataset root folder.
    """
    def dataset_function():
        return nastar_json_to_detectron_dataset(json_path, images_root)
    return dataset_function


def nastar_json_to_detectron_dataset(json_path, images_root):
    """
    Load NASTaR COCO OBB JSON and convert to Detectron2 dataset format.

    Each entry in the returned list is a dict with:
        - id: int
        - file_name: absolute path to the image
        - width, height: image dimensions
        - annotations: list of dicts with bbox, bbox_mode, category_id
    """
    assert os.path.isfile(json_path), \
        f"NASTaR JSON not found: {json_path}"

    with open(json_path, "r") as f:
        coco_data = json.load(f)

    # Build image_id -> image info mapping
    images_by_id = {}
    for img in coco_data["images"]:
        images_by_id[img["id"]] = {
            "id": img["id"],
            "file_name": os.path.join(images_root, img["file_name"]),
            "width": img["width"],
            "height": img["height"],
            "annotations": [],
        }

    # Attach annotations to their images
    for ann in coco_data["annotations"]:
        img_id = ann["image_id"]
        if img_id not in images_by_id:
            continue

        images_by_id[img_id]["annotations"].append({
            "bbox_mode": 4,  # Oriented bounding box (cx, cy, w, h, angle)
            "category_id": ann["category_id"] - 1,  # COCO 1-indexed -> Detectron 0-indexed
            "bbox": tuple(ann["bbox"]),  # (cx, cy, w, h, angle_deg)
            "iscrowd": ann.get("iscrowd", 0),
        })

    # Convert to list, keeping only images that have annotations
    dataset = []
    for img_id in sorted(images_by_id.keys()):
        entry = images_by_id[img_id]
        if len(entry["annotations"]) > 0:
            dataset.append(entry)

    return dataset